mapper.select:
SELECT a.*, d.dept_name, u.nickname AS manager_name, c.name AS category_name FROM sys_asset a LEFT JOIN sys_dept d ON a.dept_id = d.dept_id LEFT JOIN sys_user u ON a.manager_id = u.user_id LEFT JOIN asset_category c ON a.category_id = c.id WHERE a.deleted = 0
AND (a.asset_name LIKE CONCAT('%', #{query.keyword}, '%') OR a.asset_code LIKE CONCAT('%', #{query.keyword}, '%') OR a.brand LIKE CONCAT('%', #{query.keyword}, '%'))
AND a.category_id = #{query.categoryId}
AND a.dept_id = #{query.deptId}
AND a.status = #{query.status}
${query.dataScope}
ORDER BY a.create_time DESC
